"""Sync surface, async delivery.

The public client is fully synchronous and fire-and-forget: a call validates the
payload on the *calling thread* (so a bad call raises immediately, in the
caller's stack) and then hands a serialized record to a background worker thread
that does the actual HTTP, with retry and optional durable spooling.

Idempotency: ``submission_id`` is minted once, at enqueue time, and reused on
every retry — including a replay loaded from the spool after a restart — so the
server's ``(install_id, submission_id)`` dedup turns retries into no-ops.
"""

from __future__ import annotations

import queue
import threading
import time
import uuid
from dataclasses import dataclass
from typing import Callable, Literal, Optional

import httpx
from pydantic import BaseModel

from .spool import Spool

# Per-category minimal-mode policy: True = muted (dropped) when mode="minimal".
# This map is meant to be EXHAUSTIVE over the categories the route table can carry:
# Transport.__init__ asserts every category present in the routes has an entry here,
# so adding a new category server-side forces an explicit mute decision instead of
# silently defaulting to "delivered" (which a leak-prone omission would do).
CATEGORY_MUTED_IN_MINIMAL: dict[str, bool] = {
    "product": True,
    "diagnostic": False,
    "identity": False,
    "bootstrap": False,
    "consent": False,
}
# Derived: the set of categories muted under mode="minimal".
MUTED_IN_MINIMAL = frozenset(c for c, muted in CATEGORY_MUTED_IN_MINIMAL.items() if muted)

Mode = Literal["full", "minimal"]
VALID_MODES = frozenset({"full", "minimal"})

# Retry policy. 5xx is always retried; these extra (4xx) statuses are also retried.
# Everything else 4xx is treated as permanent (bad data, not worth retrying). Pass
# `retry_statuses` to the Transport to extend this if the backend adopts another
# retryable status (e.g. 409/423/425).
DEFAULT_RETRY_STATUSES = frozenset({429})

# Per-request meta auto-filled at enqueue time, keyed by the model field name.
# A field is only filled when the route's model actually declares it, so this set
# is a superset that stays in step with the backend's IngestMeta (the generator
# strips exactly these names from public signatures).
META_FILLERS: dict[str, Callable[[], object]] = {
    "ts": time.time,
    "submission_id": lambda: str(uuid.uuid4()),
}


@dataclass(frozen=True)
class Route:
    """One ingest endpoint. Emitted into the generated route table."""

    method: str
    path: str
    model: type[BaseModel]
    auth: bool
    category: str


@dataclass
class Record:
    """A validated, serialized event in flight."""

    route_key: str
    body: dict
    submission_id: Optional[str]
    spool_key: str
    attempts: int = 0


DropCallback = Callable[[Record, Optional[int]], None]


class Transport:
    def __init__(
        self,
        *,
        base_url: str,
        token: Optional[str],
        routes: dict[str, Route],
        mode: Mode = "full",
        spool: Optional[Spool] = None,
        http_client: Optional[httpx.Client] = None,
        max_attempts: int = 8,
        backoff_base: float = 0.5,
        backoff_cap: float = 30.0,
        retry_statuses: frozenset[int] = DEFAULT_RETRY_STATUSES,
        on_drop: Optional[DropCallback] = None,
    ) -> None:
        self.base_url = base_url.rstrip("/")
        self.token = token
        self.routes = routes
        # Guard the opt-out policy: every category actually used by a route must have
        # an explicit minimal-mode decision, so a new (or renamed) category can't
        # silently default to "delivered" and leak telemetry under mode="minimal".
        present = {route.category for route in routes.values()}
        uncovered = present - set(CATEGORY_MUTED_IN_MINIMAL)
        if uncovered:
            raise ValueError(
                f"CATEGORY_MUTED_IN_MINIMAL has no entry for route categories "
                f"{sorted(uncovered)}; add each with an explicit mute decision "
                "(True = muted under mode='minimal')."
            )
        if mode not in VALID_MODES:
            # Without this, any typo (e.g. "minimul") falls through enabled_for as
            # "not full" and silently mutes all product telemetry.
            raise ValueError(f"mode must be one of {sorted(VALID_MODES)}, got {mode!r}")
        self.mode = mode
        self.spool = spool
        self.client = http_client or httpx.Client(timeout=10.0)
        self.owns_client = http_client is None
        self.max_attempts = max_attempts
        self.backoff_base = backoff_base
        self.backoff_cap = backoff_cap
        self.retry_statuses = retry_statuses
        self.on_drop = on_drop

        self.queue: "queue.Queue[Record]" = queue.Queue()
        self.stopping = threading.Event()

        # Resume anything left in the spool from a previous run (same submission_id).
        if self.spool is not None:
            for spool_key, rec in self.spool.load():
                self.queue.put(
                    Record(
                        route_key=rec["route_key"],
                        body=rec["body"],
                        submission_id=rec.get("submission_id"),
                        spool_key=spool_key,
                        attempts=int(rec.get("attempts", 0)),
                    )
                )

        self.worker = threading.Thread(
            target=self.run, name="swarm-analytics", daemon=True
        )
        self.worker.start()

    # --- enqueue path (caller thread) --------------------------------------

    def enabled_for(self, category: str) -> bool:
        if self.mode == "full":
            return True
        return category not in MUTED_IN_MINIMAL

    def is_retryable_status(self, status: int) -> bool:
        """Whether an HTTP status warrants a retry: any 5xx, plus the configured
        extra (4xx) statuses. Everything else is permanent."""
        return status in self.retry_statuses or 500 <= status < 600

    def build_model(self, route: Route, fields: dict) -> BaseModel:
        """Validate on the caller's thread, auto-filling per-request meta."""
        data = dict(fields)
        model_fields = route.model.model_fields
        for field, filler in META_FILLERS.items():
            if field in model_fields:
                data.setdefault(field, filler())
        return route.model(**data)  # raises pydantic.ValidationError on bad input

    def send(self, route_key: str, fields: dict) -> None:
        route = self.routes[route_key]
        if not self.enabled_for(route.category):
            return
        model = self.build_model(route, fields)
        submission_id = getattr(model, "submission_id", None)
        body = model.model_dump(by_alias=True, mode="json")
        spool_key = submission_id or str(uuid.uuid4())
        if self.spool is not None:
            self.spool.add(spool_key, self.as_spool_record(route_key, body, submission_id, 0))
        self.queue.put(
            Record(route_key=route_key, body=body, submission_id=submission_id, spool_key=spool_key)
        )

    @staticmethod
    def as_spool_record(route_key: str, body: dict, submission_id: Optional[str], attempts: int) -> dict:
        return {"route_key": route_key, "body": body, "submission_id": submission_id, "attempts": attempts}

    # --- delivery path (worker thread) -------------------------------------

    def run(self) -> None:
        while not self.stopping.is_set():
            try:
                rec = self.queue.get(timeout=0.2)
            except queue.Empty:
                continue
            try:
                self.deliver(rec)
            except Exception:
                # One bad record must never kill the worker — that would silently
                # stop ALL delivery for the process's lifetime. The realistic
                # trigger is a stale spooled record whose route_key no longer
                # exists in the table (e.g. a namespace/method was renamed in an
                # SDK upgrade), which KeyErrors on the route lookup in deliver().
                # Drop it (surfaced via on_drop with status=None) and keep going.
                self.drop(rec, None)
            finally:
                self.queue.task_done()

    def deliver(self, rec: Record) -> None:
        route = self.routes[rec.route_key]
        url = self.base_url + route.path
        headers = {"Content-Type": "application/json"}
        if route.auth and self.token:
            headers["Authorization"] = f"Bearer {self.token}"

        while True:
            status = self.attempt(route.method, url, rec.body, headers)
            if status is not None and 200 <= status < 300:
                self.finish(rec)
                return
            if status is not None and not self.is_retryable_status(status):
                # Permanent (non-retryable 4xx): bad data, not worth retrying.
                self.drop(rec, status)
                return
            rec.attempts += 1
            if rec.attempts >= self.max_attempts:
                self.drop(rec, status)
                return
            if self.spool is not None:
                self.spool.add(
                    rec.spool_key,
                    self.as_spool_record(rec.route_key, rec.body, rec.submission_id, rec.attempts),
                )
            delay = min(self.backoff_cap, self.backoff_base * (2 ** (rec.attempts - 1)))
            # Wake early on shutdown; leave the record in the spool for next run.
            if self.stopping.wait(delay):
                return

    def attempt(self, method: str, url: str, body: dict, headers: dict) -> Optional[int]:
        """Return the HTTP status, or None for a network-level failure (retryable)."""
        try:
            resp = self.client.request(method, url, json=body, headers=headers)
            return resp.status_code
        except (httpx.TimeoutException, httpx.TransportError):
            return None

    def finish(self, rec: Record) -> None:
        self.spool_remove(rec.spool_key)

    def drop(self, rec: Record, status: Optional[int]) -> None:
        self.spool_remove(rec.spool_key)
        if self.on_drop is not None:
            # A user callback raising here would otherwise propagate out of the
            # worker thread and kill it; swallow so delivery keeps running.
            try:
                self.on_drop(rec, status)
            except Exception:
                pass

    def spool_remove(self, spool_key: str) -> None:
        """Remove a record from the spool, swallowing any backend error so a
        transient spool failure can't take down the delivery worker."""
        if self.spool is None:
            return
        try:
            self.spool.remove(spool_key)
        except Exception:
            pass

    # --- lifecycle ---------------------------------------------------------

    def flush(self, timeout: Optional[float] = None) -> bool:
        """Block until the queue drains (or timeout). Returns True if fully drained."""
        deadline = None if timeout is None else time.monotonic() + timeout
        while self.queue.unfinished_tasks > 0:
            if deadline is not None and time.monotonic() >= deadline:
                return False
            time.sleep(0.02)
        return True

    def close(self) -> None:
        self.stopping.set()
        self.worker.join(timeout=2.0)
        if self.owns_client:
            self.client.close()
